const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

let initialized = false;

function initializeClients() {
  if (initialized) return;

  const sendGridApiKey = process.env.SENDGRID_API_KEY;
  const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
  const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;

  if (!sendGridApiKey) {
    throw new Error('Missing required environment variable: SENDGRID_API_KEY');
  }
  if (!twilioAccountSid) {
    throw new Error('Missing required environment variable: TWILIO_ACCOUNT_SID');
  }
  if (!twilioAuthToken) {
    throw new Error('Missing required environment variable: TWILIO_AUTH_TOKEN');
  }

  sgMail.setApiKey(sendGridApiKey);
  global.twilioClient = twilio(twilioAccountSid, twilioAuthToken);

  initialized = true;
}

async function sendEmail(email) {
  const from = email.from || process.env.SENDGRID_FROM_EMAIL;
  const to = email.to;
  const subject = email.subject;
  const text = email.text;
  const html = email.html;

  if (!from) throw new Error('Missing email.from or SENDGRID_FROM_EMAIL');
  if (!to) throw new Error('Missing email.to');
  if (!subject) throw new Error('Missing email.subject');
  if (!text && !html) throw new Error('Missing email.text or email.html');

  const msg = {
    to,
    from,
    subject,
    text: text || undefined,
    html: html || undefined,
  };

  return sgMail.send(msg);
}

async function sendSms(sms) {
  const from = sms.from || process.env.TWILIO_FROM_NUMBER;
  const to = sms.to;
  const body = sms.body;

  if (!from) throw new Error('Missing sms.from or TWILIO_FROM_NUMBER');
  if (!to) throw new Error('Missing sms.to');
  if (!body) throw new Error('Missing sms.body');

  return global.twilioClient.messages.create({
    from,
    to,
    body,
  });
}

functions.http('sendNotification', async (req, res) => {
  try {
    initializeClients();

    if (req.method !== 'POST') {
      res.status(405).json({ error: 'Method not allowed. Use POST.' });
      return;
    }

    const payload = typeof req.body === 'string' ? JSON.parse(req.body) : (req.body || {});
    const { email, sms } = payload;

    if (!email && !sms) {
      res.status(400).json({ error: 'Request body must include email and/or sms object.' });
      return;
    }

    const result = {
      email: null,
      sms: null,
    };

    if (email) {
      const emailResponse = await sendEmail(email);
      result.email = {
        success: true,
        response: Array.isArray(emailResponse) ? emailResponse.map((r) => r && r.statusCode ? { statusCode: r.statusCode } : null) : null,
      };
    }

    if (sms) {
      const smsResponse = await sendSms(sms);
      result.sms = {
        success: true,
        sid: smsResponse.sid,
        status: smsResponse.status,
      };
    }

    res.status(200).json(result);
  } catch (error) {
    console.error(error);

    const isAuthError =
      error && (
        error.code === 401 ||
        error.statusCode === 401 ||
        /unauthori[sz]ed/i.test(error.message || '') ||
        /authentication/i.test(error.message || '')
      );

    res.status(isAuthError ? 401 : 500).json({
      error: error.message || 'Internal server error',
    });
  }
});